// Check who has been silent for more than 48 hours.
// We prioritize Telegram DM, fall back to email if the Telegram node fails (see Route by channel node).

const students = $('Read students').all().map(i => i.json);
const messages = $('Read messages').all().map(i => i.json);
const thresholdHours = 48;
const now = new Date();

const output = [];

for (const student of students) {
  if (String(student.active).toUpperCase() !== 'TRUE') continue;

  const userMsgs = messages.filter(m =>
    String(m.telegram_user_id) === String(student.telegram_user_id)
  );

  let lastMsgDate = null;
  if (userMsgs.length > 0) {
    lastMsgDate = new Date(
      Math.max(...userMsgs.map(m => new Date(m.timestamp).getTime()))
    );
  }

  const hoursSilent = lastMsgDate
    ? Math.floor((now - lastMsgDate) / (1000 * 60 * 60))
    : 9999;

  if (hoursSilent >= thresholdHours) {
    // Channel cascade: Telegram first (free + personal), email as fallback.
    // WhatsApp will slot in between these two in v2.
    const hasTelegramId = student.telegram_user_id && String(student.telegram_user_id).trim() !== '';
    const primary_channel = hasTelegramId ? 'telegram' : 'email';

    output.push({
      json: {
        telegram_user_id: student.telegram_user_id,
        first_name: student.first_name,
        email: student.email,
        primary_channel: primary_channel,
        hours_silent: hoursSilent,
        days_silent: Math.floor(hoursSilent / 24),
        last_message_date: lastMsgDate ? lastMsgDate.toISOString() : 'jamais'
      }
    });
  }
}

return output;
